<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Http\Requests\Admin\UserRequest; use App\Models\{User,Role,Permission}; use App\Services\Admin\{UserService,ActivityLogger}; use Illuminate\Http\Request;
class UserController extends Controller { public function index(Request $r){$q=User::query()->with('roles'); if($r->filled('search')) $q->where(fn($x)=>$x->where('name','like','%'.$r->search.'%')->orWhere('email','like','%'.$r->search.'%')); if($r->filled('status')) $q->where('status',$r->status); return view('admin.users.index',['users'=>$q->latest()->paginate(15)]);} public function create(){return view('admin.users.form',['user'=>new User,'roles'=>Role::all(),'permissions'=>Permission::all()]);} public function store(UserRequest $r, UserService $s, ActivityLogger $l){$u=$s->save($r->validated()); $l->log('created','Created user '.$u->email,$u); return redirect()->route('admin.users.index');} public function edit(User $user){return view('admin.users.form',['user'=>$user,'roles'=>Role::all(),'permissions'=>Permission::all()]);} public function update(UserRequest $r, User $user, UserService $s, ActivityLogger $l){$s->save($r->validated(),$user); $l->log('updated','Updated user '.$user->email,$user); return redirect()->route('admin.users.index');} public function destroy(User $user, ActivityLogger $l){$l->log('deleted','Deleted user '.$user->email,$user); $user->delete(); return back();} }
